//! protocol69-pluto-agent — local Pluto preflight collector for workflow queues.
//!
//! This binary is intentionally narrow: it claims `CollectPlutoPreflight` work from
//! `gnosis-foil-control`, calls the fail-closed `skymesh-wifi-pluto` preflight
//! endpoint, and returns a certificate-bearing protocol69 input ack.

use distributed_inference::protocol69::{
    build_protocol69_pluto_preflight_ack, validate_protocol69_input_ack, Protocol69AgentAck,
    Protocol69DispatchClaim, Protocol69InRoomAgent, Protocol69PlutoPreflightObservation,
    Protocol69WorkflowFrame, WorkflowExecutor, WorkflowWorkKind,
};
use serde::{Deserialize, Serialize};
use std::time::Duration;

const DEFAULT_FOIL_URL: &str = "http://127.0.0.1:8787";
const DEFAULT_PLUTO_URL: &str = "http://127.0.0.1:18732";
const DEFAULT_AGENT_ID: &str = "pluto-bridge-local";
const DEFAULT_POLL_MS: u64 = 1_000;

#[derive(Debug, Clone, PartialEq, Eq)]
struct Cli {
    foil_url: String,
    pluto_url: String,
    agent_id: String,
    poll_ms: u64,
    once: bool,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
struct PlutoBridgePreflight {
    framework: String,
    iio_attr: String,
    iio_writedev: String,
    libiio_build: String,
    ok: bool,
    pluto_uri: String,
    reason: Option<String>,
    tx_enabled: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum AgentStep {
    Idle,
    Completed { dispatch_id: String },
}

fn parse_cli() -> Result<Cli, String> {
    let mut cli = Cli {
        foil_url: DEFAULT_FOIL_URL.to_string(),
        pluto_url: DEFAULT_PLUTO_URL.to_string(),
        agent_id: DEFAULT_AGENT_ID.to_string(),
        poll_ms: DEFAULT_POLL_MS,
        once: false,
    };

    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--foil-url" => cli.foil_url = args.next().ok_or("--foil-url requires a value")?,
            "--pluto-url" => cli.pluto_url = args.next().ok_or("--pluto-url requires a value")?,
            "--agent-id" => cli.agent_id = args.next().ok_or("--agent-id requires a value")?,
            "--poll-ms" => {
                cli.poll_ms = args
                    .next()
                    .ok_or("--poll-ms requires a value")?
                    .parse()
                    .map_err(|_| "--poll-ms must be a positive integer".to_string())?;
                if cli.poll_ms == 0 {
                    return Err("--poll-ms must be positive".to_string());
                }
            }
            "--once" => cli.once = true,
            "--help" | "-h" => return Err(usage()),
            other => return Err(format!("unknown arg {other}\n{}", usage())),
        }
    }
    Ok(cli)
}

fn usage() -> String {
    "usage: protocol69-pluto-agent [--foil-url URL] [--pluto-url URL] [--agent-id ID] [--poll-ms N] [--once]".to_string()
}

fn workflow_agent(agent_id: &str) -> Result<Protocol69InRoomAgent, String> {
    Protocol69InRoomAgent::new(
        agent_id,
        WorkflowExecutor::LocalAgent,
        vec![WorkflowWorkKind::CollectPlutoPreflight],
    )
}

fn observation_from_preflight(
    bridge_url: &str,
    preflight: PlutoBridgePreflight,
) -> Protocol69PlutoPreflightObservation {
    Protocol69PlutoPreflightObservation {
        bridge_url: bridge_url.trim_end_matches('/').to_string(),
        pluto_uri: preflight.pluto_uri,
        ok: preflight.ok,
        tx_enabled: preflight.tx_enabled,
        framework: preflight.framework,
        iio_attr: preflight.iio_attr,
        iio_writedev: preflight.iio_writedev,
    }
}

fn ack_for_claimed_pluto_frame(
    pluto_url: &str,
    frame: &Protocol69WorkflowFrame,
    preflight: PlutoBridgePreflight,
) -> Result<Protocol69AgentAck, String> {
    if frame.executor != WorkflowExecutor::LocalAgent
        || frame.work_kind != WorkflowWorkKind::CollectPlutoPreflight
    {
        return Err("claimed frame is not local CollectPlutoPreflight work".to_string());
    }
    let observation = observation_from_preflight(pluto_url, preflight);
    let ack = build_protocol69_pluto_preflight_ack(
        frame.workflow_id.clone(),
        frame.dispatch_id.clone(),
        &observation,
    )?;
    validate_protocol69_input_ack(&ack)?;
    Ok(Protocol69AgentAck::Input { ack })
}

fn normalize_base_url(url: &str) -> String {
    url.trim_end_matches('/').to_string()
}

fn get_preflight(agent: &ureq::Agent, pluto_url: &str) -> Result<PlutoBridgePreflight, String> {
    let url = format!("{}/pluto/preflight", normalize_base_url(pluto_url));
    agent
        .get(&url)
        .call()
        .map_err(|error| format!("GET {url} failed: {error}"))?
        .into_json::<PlutoBridgePreflight>()
        .map_err(|error| format!("decode Pluto preflight failed: {error}"))
}

fn claim_work(
    agent: &ureq::Agent,
    foil_url: &str,
    local_agent: &Protocol69InRoomAgent,
) -> Result<Protocol69DispatchClaim, String> {
    let url = format!(
        "{}/.aeon/protocol69/workflow/claim",
        normalize_base_url(foil_url)
    );
    let body = serde_json::to_vec(local_agent).map_err(|error| error.to_string())?;
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_bytes(&body)
        .map_err(|error| format!("POST {url} failed: {error}"))?
        .into_json::<Protocol69DispatchClaim>()
        .map_err(|error| format!("decode workflow claim failed: {error}"))
}

fn post_ack(
    agent: &ureq::Agent,
    foil_url: &str,
    ack: &Protocol69AgentAck,
) -> Result<serde_json::Value, String> {
    let url = format!(
        "{}/.aeon/protocol69/workflow/ack",
        normalize_base_url(foil_url)
    );
    let body = serde_json::to_vec(ack).map_err(|error| error.to_string())?;
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_bytes(&body)
        .map_err(|error| format!("POST {url} failed: {error}"))?
        .into_json::<serde_json::Value>()
        .map_err(|error| format!("decode workflow ack response failed: {error}"))
}

fn run_once(http: &ureq::Agent, cli: &Cli) -> Result<AgentStep, String> {
    let local_agent = workflow_agent(&cli.agent_id)?;
    let claim = claim_work(http, &cli.foil_url, &local_agent)?;
    if claim.status == "idle" {
        return Ok(AgentStep::Idle);
    }
    if claim.status != "claimed" {
        return Err(format!("unexpected workflow claim status {}", claim.status));
    }
    let frame = claim
        .frame
        .as_ref()
        .ok_or_else(|| "claimed response omitted frame".to_string())?;
    let preflight = get_preflight(http, &cli.pluto_url)?;
    let ack = ack_for_claimed_pluto_frame(&cli.pluto_url, frame, preflight)?;
    post_ack(http, &cli.foil_url, &ack)?;
    Ok(AgentStep::Completed {
        dispatch_id: frame.dispatch_id.clone(),
    })
}

fn run(cli: Cli) -> Result<(), String> {
    let http = ureq::AgentBuilder::new()
        .timeout_connect(Duration::from_secs(2))
        .timeout_read(Duration::from_secs(5))
        .timeout_write(Duration::from_secs(5))
        .build();

    loop {
        match run_once(&http, &cli)? {
            AgentStep::Idle => {
                if cli.once {
                    println!("protocol69-pluto-agent idle");
                    return Ok(());
                }
                std::thread::sleep(Duration::from_millis(cli.poll_ms));
            }
            AgentStep::Completed { dispatch_id } => {
                println!("protocol69-pluto-agent completed {dispatch_id}");
                if cli.once {
                    return Ok(());
                }
            }
        }
    }
}

fn main() {
    match parse_cli().and_then(run) {
        Ok(()) => {}
        Err(error) => {
            eprintln!("{error}");
            std::process::exit(2);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use distributed_inference::protocol69::{
        build_protocol69_projection_envelope, build_protocol69_workflow_certificate,
        validate_protocol69_input_ack, LazyAckState, Protocol69DispatchQueueSummary,
        Protocol69WorkflowAction, Protocol69WorkflowFrame, PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID,
        PROTOCOL69_DISPATCH_CLAIM_SCHEMA_VERSION, PROTOCOL69_DISPATCH_SUMMARY_CONTRACT_ID,
        PROTOCOL69_DISPATCH_SUMMARY_SCHEMA_VERSION, PROTOCOL69_WORKFLOW_CONTRACT_ID,
        PROTOCOL69_WORKFLOW_SCHEMA_VERSION,
    };
    use std::net::TcpListener;
    use std::thread;
    use tiny_http::{Header, Method, Response, Server, StatusCode};

    fn pluto_frame() -> Protocol69WorkflowFrame {
        Protocol69WorkflowFrame {
            schema_version: PROTOCOL69_WORKFLOW_SCHEMA_VERSION.to_string(),
            contract_id: PROTOCOL69_WORKFLOW_CONTRACT_ID.to_string(),
            certificate: build_protocol69_workflow_certificate(),
            workflow_id: "workflow-pluto".to_string(),
            dispatch_id: "workflow-pluto:collect-pluto-preflight".to_string(),
            action: Protocol69WorkflowAction::DispatchInputCollection,
            state: LazyAckState::Dispatched,
            executor: WorkflowExecutor::LocalAgent,
            work_kind: WorkflowWorkKind::CollectPlutoPreflight,
            projection: build_protocol69_projection_envelope(),
        }
    }

    fn bridge_preflight(tx_enabled: bool) -> PlutoBridgePreflight {
        PlutoBridgePreflight {
            framework: "/tmp/libiio_build/build/iio.framework/iio".to_string(),
            iio_attr: "/tmp/libiio_build/build/tests/iio_attr".to_string(),
            iio_writedev: "/tmp/libiio_build/build/tests/iio_writedev".to_string(),
            libiio_build: "/tmp/libiio_build/build".to_string(),
            ok: true,
            pluto_uri: "usb:2.12.5".to_string(),
            reason: None,
            tx_enabled,
        }
    }

    #[test]
    fn workflow_agent_claims_only_pluto_preflight_work() {
        let agent = workflow_agent("pluto-bridge-local").expect("agent");
        let frame = pluto_frame();

        assert!(agent.can_accept(&frame));
        assert_eq!(agent.executor, WorkflowExecutor::LocalAgent);
        assert_eq!(agent.skills, vec![WorkflowWorkKind::CollectPlutoPreflight]);
    }

    #[test]
    fn bridge_preflight_maps_to_protocol69_input_ack() {
        let frame = pluto_frame();
        let ack =
            ack_for_claimed_pluto_frame("http://127.0.0.1:18732/", &frame, bridge_preflight(false))
                .expect("ack");

        let Protocol69AgentAck::Input { ack } = ack else {
            panic!("preflight must be an input ack");
        };
        validate_protocol69_input_ack(&ack).expect("ack validates");
        assert_eq!(ack.workflow_id, "workflow-pluto");
        assert_eq!(ack.dispatch_id, "workflow-pluto:collect-pluto-preflight");
        assert_eq!(ack.task.kind, WorkflowWorkKind::CollectPlutoPreflight);
        assert_eq!(ack.task.executor, WorkflowExecutor::LocalAgent);
    }

    #[test]
    fn tx_enabled_preflight_is_rejected_before_ack() {
        let error = ack_for_claimed_pluto_frame(
            "http://127.0.0.1:18732",
            &pluto_frame(),
            bridge_preflight(true),
        )
        .expect_err("tx enabled rejected");

        assert!(error.contains("txEnabled=false"));
    }

    #[test]
    fn non_pluto_frame_is_rejected() {
        let mut frame = pluto_frame();
        frame.work_kind = WorkflowWorkKind::CollectPingLatency;

        let error =
            ack_for_claimed_pluto_frame("http://127.0.0.1:18732", &frame, bridge_preflight(false))
                .expect_err("wrong work kind rejected");

        assert!(error.contains("CollectPlutoPreflight"));
    }

    fn free_port() -> u16 {
        TcpListener::bind("127.0.0.1:0")
            .expect("bind free port")
            .local_addr()
            .expect("local addr")
            .port()
    }

    fn json_response<T: Serialize>(value: &T, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
        let body = serde_json::to_vec(value).expect("json body");
        Response::from_data(body)
            .with_status_code(StatusCode(status))
            .with_header(
                Header::from_bytes(
                    &b"Content-Type"[..],
                    &b"application/json; charset=utf-8"[..],
                )
                .expect("content-type header"),
            )
    }

    fn queue_summary() -> Protocol69DispatchQueueSummary {
        Protocol69DispatchQueueSummary {
            schema_version: PROTOCOL69_DISPATCH_SUMMARY_SCHEMA_VERSION.to_string(),
            contract_id: PROTOCOL69_DISPATCH_SUMMARY_CONTRACT_ID.to_string(),
            pending: 0,
            claimed: 1,
            completed: 0,
            rejected: 0,
            timestamp_ms: 1,
        }
    }

    fn start_fake_foil_server(port: u16, frame: Protocol69WorkflowFrame) -> thread::JoinHandle<()> {
        thread::spawn(move || {
            let server = Server::http(format!("127.0.0.1:{port}")).expect("foil server");
            for mut request in server.incoming_requests().take(2) {
                let path = request.url().split('?').next().unwrap_or("/").to_string();
                let mut body = String::new();
                request
                    .as_reader()
                    .read_to_string(&mut body)
                    .expect("read request body");
                match (request.method(), path.as_str()) {
                    (&Method::Post, "/.aeon/protocol69/workflow/claim") => {
                        let agent: Protocol69InRoomAgent =
                            serde_json::from_str(&body).expect("claim agent");
                        assert_eq!(agent.executor, WorkflowExecutor::LocalAgent);
                        assert_eq!(agent.skills, vec![WorkflowWorkKind::CollectPlutoPreflight]);
                        let claim = serde_json::json!({
                            "schemaVersion": PROTOCOL69_DISPATCH_CLAIM_SCHEMA_VERSION,
                            "contractId": PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID,
                            "status": "claimed",
                            "agentId": agent.agent_id,
                            "dispatchId": frame.dispatch_id.clone(),
                            "frame": frame.clone(),
                            "summary": queue_summary(),
                            "projection": build_protocol69_projection_envelope(),
                        });
                        request
                            .respond(json_response(&claim, 200))
                            .expect("claim response");
                    }
                    (&Method::Post, "/.aeon/protocol69/workflow/ack") => {
                        let ack: Protocol69AgentAck =
                            serde_json::from_str(&body).expect("protocol69 ack");
                        let Protocol69AgentAck::Input { ack } = ack else {
                            panic!("expected input ack");
                        };
                        validate_protocol69_input_ack(&ack).expect("ack validates");
                        assert_eq!(ack.task.kind, WorkflowWorkKind::CollectPlutoPreflight);
                        let response = serde_json::json!({
                            "status": "accepted",
                            "service": "gnosis-foil",
                            "transport": "http",
                            "accepted": true,
                            "summary": {
                                "schemaVersion": PROTOCOL69_DISPATCH_SUMMARY_SCHEMA_VERSION,
                                "contractId": PROTOCOL69_DISPATCH_SUMMARY_CONTRACT_ID,
                                "pending": 0,
                                "claimed": 0,
                                "completed": 1,
                                "rejected": 0,
                                "timestampMs": 2
                            }
                        });
                        request
                            .respond(json_response(&response, 200))
                            .expect("ack response");
                    }
                    _ => request
                        .respond(json_response(
                            &serde_json::json!({"error": "not found"}),
                            404,
                        ))
                        .expect("not found response"),
                }
            }
        })
    }

    fn start_fake_pluto_server(port: u16) -> thread::JoinHandle<()> {
        thread::spawn(move || {
            let server = Server::http(format!("127.0.0.1:{port}")).expect("pluto server");
            let request = server.recv().expect("preflight request");
            assert_eq!(request.method(), &Method::Get);
            assert_eq!(request.url(), "/pluto/preflight");
            request
                .respond(json_response(&bridge_preflight(false), 200))
                .expect("preflight response");
        })
    }

    #[test]
    fn run_once_claims_preflight_and_posts_ack_over_http() {
        let foil_port = free_port();
        let pluto_port = free_port();
        let foil = start_fake_foil_server(foil_port, pluto_frame());
        let pluto = start_fake_pluto_server(pluto_port);
        let cli = Cli {
            foil_url: format!("http://127.0.0.1:{foil_port}"),
            pluto_url: format!("http://127.0.0.1:{pluto_port}"),
            agent_id: "pluto-bridge-local".to_string(),
            poll_ms: 1,
            once: true,
        };
        let http = ureq::AgentBuilder::new()
            .timeout_connect(Duration::from_secs(2))
            .timeout_read(Duration::from_secs(2))
            .timeout_write(Duration::from_secs(2))
            .build();

        let step = run_once(&http, &cli).expect("run once");

        assert_eq!(
            step,
            AgentStep::Completed {
                dispatch_id: "workflow-pluto:collect-pluto-preflight".to_string()
            }
        );
        foil.join().expect("foil server joined");
        pluto.join().expect("pluto server joined");
    }
}
